SELECT game_name
FROM lottery_games
WHERE prize_tiers = (SELECT MAX(prize_tiers) FROM lottery_games);

SELECT num_draws_per_week
FROM lottery_games
WHERE game_id = 1;

SELECT SUM(prize_amount) AS total_prize_distributed
FROM prize_distributions
WHERE country_id = 1;

SELECT game_name, prize_tiers, min_prize_amount, max_prize_amount
FROM lottery_games
ORDER BY prize_tiers DESC;

SELECT prize_tier_name, SUM(prize_amount) AS total_prize_amount
FROM prize_tiers
GROUP BY prize_tier_name;

SELECT draw_date, prize_fund
FROM draws
WHERE draw_id = 0;

SELECT num_tickets_sold, AVG(prize_fund) AS average_prize_fund
FROM draws
WHERE draw_status = 'completed';

SELECT MAX(prize_amount) AS max_prize
FROM winners
WHERE draw_id = 0;
